"use strict";const t=require("./request.js");exports.addCartItem=function(e){return t.request("/cart/items",{method:"POST",data:e})},exports.deleteCartItem=function(e){return t.request(`/cart/items/${e}`,{method:"DELETE"})},exports.getCart=function(){return t.request("/cart")},exports.updateCartItem=function(e,r){return t.request(`/cart/items/${e}`,{method:"PATCH",data:{quantity:r}})};
